import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode() {}
    TreeNode(int val) { this.val = val; }
    TreeNode(int val, TreeNode left, TreeNode right) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

public List<List<Integer>> findMinMax(TreeNode root, int[] queries) {
    if (root == null) {
        return new ArrayList<>();
    }

    List<List<Integer>> ans = new ArrayList<>();
    for (int query : queries) {
        TreeNode node = root;
        List<Integer> currentList = Arrays.asList(-1, -1);
        while (node != null) {
            if (node.val < query) {
                currentList.set(0, node.val);
                node = node.right;
            } else {
                currentList.set(1, node.val);
                if (node.val == query) {
                    currentList.set(0, query);
                    break;
                }
                node = node.left;
            }
        }
        ans.add(currentList);
    }
    return ans;
}
```

    For every query, start from the root of the binary search tree. If the node's value is less than the query, update the minValue in answer for that query and move to the right child. If the node's value is equal or greater than the query, update the maxValue and, if it is equal, update the minValue as well; then move to the left child. Keep doing this until the node becomes null.
